@spec mm_signal_flow_spec  src=tests/specs/mm_signal_flow_spec.lua  loc=218  sha=37ed80d  cases=12
@exercises harness (harness), midiManager (h.fm), trackerManager (h.tm)
@surface   harness.mk, fm:load, fm:take, fm:subscribe, fm:modify, tm:subscribe, harness.bareMM, fm:notes, fm:assign
@harness   mk, bareMM, reaper.MIDI_InsertNote, reaper:seedMidi

# Intent
  Pin-tests for the mm → tm signal split landed in the callbacks revamp.
  
  Contract under test:
    * mm fires `takeSwapped` only when mm:load receives a different take,
      and always BEFORE its `reload` fire on that load.
    * mm fires `reload` on every load, with no payload.
    * tm forwards `takeSwapped` to its own subscribers and consumes the
      flag transiently, calling tm:rebuild(true) on the next reload.
    * tm fires `rebuild` (no payload) on every rebuild.
    * The takeSwapped flag is one-shot: a subsequent same-take reload
      does not re-fire takeSwapped and tm:rebuild sees takeChanged=false.

# Helpers
  @fn recordOn(owner, signals)  @ 19-25
      -- Records the sequence of signals fired on a single owner. Listener order
      -- across owners is non-deterministic (set iteration), so each owner gets
      -- its own stream and ordering assertions stay within one source.

# Cases
  @case 'mm:load with a different take fires mm.takeSwapped before mm.reload'  [pure]  @ 29-41
  @case 'mm:load with the same take fires reload only'  [pure]  @ 45-56
  @case 'takeSwapped is one-shot: next same-take reload sees takeChanged=false'  [pure]  @ 60-76
  @case 'mm.reload carries wholesale: true from load, false from modify'  [pure]  @ 82-100
  @case 'tm.rebuild forwards takeChanged (so gm can reload take-tier state)'  [pure]  @ 104-112
  @case 'multiple subscribers on the same signal both fire'  [pure]  @ 116-125
  @case 'mm.reload chans: an add marks only the touched channel'  [pure]  @ 131-141
  @case 'mm.reload chans: an assign changing chan marks both old and new'  [pure]  @ 145-154
  @case 'mm.reload chans: a wholesale load carries no chans (nil = all 16)'  [pure]  @ 158-167
  @case 'mm.reload: a load finding the take converged gates — not wholesale, no dirty chans'  [pure]  @ 174-182
  @case 'mm.flushed fires after reload on a structural modify, not on a clean one'  [pure]  @ 189-200
  @case 'mm.flushed fires on a load that reprojected the take, silent on the clean re-load'  [pure]  @ 204-216

